import math
import time

ROW_COUNT = 6
COLUMN_COUNT = 7
WINDOW_LENGTH = 4

def create_board():
    return [[' ' for _ in range(COLUMN_COUNT)] for _ in range(ROW_COUNT)]

def is_valid_location(board, col):
    return board[0][col] == ' '

def get_next_open_row(board, col):
    for r in range(ROW_COUNT - 1, -1, -1):
        if board[r][col] == ' ':
            return r

def drop_piece(board, row, col, piece):
    board[row][col] = piece

def winning_move(board, piece):
    for c in range(COLUMN_COUNT - 3):
        for r in range(ROW_COUNT):
            if all(board[r][c+i] == piece for i in range(4)):
                return True
    for c in range(COLUMN_COUNT):
        for r in range(ROW_COUNT - 3):
            if all(board[r+i][c] == piece for i in range(4)):
                return True
    for c in range(COLUMN_COUNT - 3):
        for r in range(ROW_COUNT - 3):
            if all(board[r+i][c+i] == piece for i in range(4)):
                return True
    for c in range(COLUMN_COUNT - 3):
        for r in range(3, ROW_COUNT):
            if all(board[r-i][c+i] == piece for i in range(4)):
                return True
    return False

def get_valid_locations(board):
    return [c for c in range(COLUMN_COUNT) if is_valid_location(board, c)]

def evaluate_window(window, piece):
    score = 0
    opp_piece = 'O' if piece == 'X' else 'X'
    piece_count = window.count(piece)
    empty_count = window.count(' ')
    opp_count = window.count(opp_piece)

    if piece_count == 4:
        score += 100
    elif piece_count == 3 and empty_count == 1:
        score += 5
    elif piece_count == 2 and empty_count == 2:
        score += 2
    if opp_count == 3 and empty_count == 1:
        score -= 4
    return score

def score_position(board, piece):
    score = 0
    center_array = [board[r][COLUMN_COUNT//2] for r in range(ROW_COUNT)]
    center_count = center_array.count(piece)
    score += center_count * 3

    for c in range(COLUMN_COUNT):
        col_array = [board[r][c] for r in range(ROW_COUNT)]
        for r in range(ROW_COUNT - 3):
            window = col_array[r:r+4]
            score += evaluate_window(window, piece)
    for r in range(ROW_COUNT):
        row_array = board[r]
        for c in range(COLUMN_COUNT - 3):
            window = row_array[c:c+4]
            score += evaluate_window(window, piece)
    for r in range(ROW_COUNT - 3):
        for c in range(COLUMN_COUNT - 3):
            window = [board[r+i][c+i] for i in range(4)]
            score += evaluate_window(window, piece)
    for r in range(ROW_COUNT - 3):
        for c in range(COLUMN_COUNT - 3):
            window = [board[r+3-i][c+i] for i in range(4)]
            score += evaluate_window(window, piece)
    return score

def order_moves(board, moves, piece):
    def move_priority(col):
        row = get_next_open_row(board, col)
        temp_board = [r[:] for r in board]
        drop_piece(temp_board, row, col, piece)
        if winning_move(temp_board, piece):
            return 0
        opp_piece = 'O' if piece == 'X' else 'X'
        drop_piece(temp_board, row, col, opp_piece)
        if winning_move(temp_board, opp_piece):
            return 1
        dist_from_center = abs(col - COLUMN_COUNT // 2)
        return 3 + dist_from_center
    return sorted(moves, key=move_priority)

def minimax(board, depth, alpha, beta, is_maximizing, piece):
    valid_locations = get_valid_locations(board)

    if winning_move(board, piece):
        return (None, float('inf'))
    if winning_move(board, 'O' if piece == 'X' else 'X'):
        return (None, -float('inf'))
    if not valid_locations:
        return (None, 0)
    if depth == 0:
        return (None, score_position(board, piece))

    valid_locations = order_moves(board, valid_locations, piece)

    if is_maximizing:
        value = -float('inf')
        column = valid_locations[0]
        for col in valid_locations:
            row = get_next_open_row(board, col)
            temp_board = [r[:] for r in board]
            drop_piece(temp_board, row, col, piece)
            new_score = minimax(temp_board, depth - 1, alpha, beta, False, piece)[1]
            if new_score > value:
                value = new_score
                column = col
            alpha = max(alpha, value)
            if alpha >= beta:
                break
        return column, value
    else:
        value = float('inf')
        column = valid_locations[0]
        opp_piece = 'O' if piece == 'X' else 'X'
        for col in valid_locations:
            row = get_next_open_row(board, col)
            temp_board = [r[:] for r in board]
            drop_piece(temp_board, row, col, opp_piece)
            new_score = minimax(temp_board, depth - 1, alpha, beta, True, piece)[1]
            if new_score < value:
                value = new_score
                column = col
            beta = min(beta, value)
            if alpha >= beta:
                break
        return column, value

def iterative_deepening(board, piece, max_time=5):
    start_time = time.time()
    best_move = get_valid_locations(board)[0]
    depth = 1

    while time.time() - start_time < max_time:
        try:
            column, score = minimax(board, depth, -float('inf'), float('inf'), True, piece)
            if column is not None:
                best_move = column
            depth += 1
        except:
            break
    return best_move

